div.p:
Transmission Order: Network Byte Order (Big Endian)
Alignment: Packed structure, 1-byte granularity.
Base Header Size: 14 bytes + Dynamic NodeID length.
Checksumming: Handled at Transport Layer (TCP/TLS).
| {
near: top-left
style: {
stroke: "#E5E7EB"
fill: "#F9FAFB"
border-radius: 8
}
}

offsets: {
grid-columns: 1
grid-gap: 20
o0: "0x00" {shape: text; style.font: mono; style.font-size: 18}
o4: "0x04" {shape: text; style.font: mono; style.font-size: 18}
o5: "0x05" {shape: text; style.font: mono; style.font-size: 18}
o6: "0x06" {shape: text; style.font: mono; style.font-size: 18}
oTs: "0x06 + N" {shape: text; style.font: mono; style.font-size: 18}
oBody: "0x0E + N" {shape: text; style.font: mono; style.font-size: 18}
}

pre.code:
length: "Length\n(4 Bytes)" { style.fill: "${colors.data}" style.stroke: "${colors.border}" style.stroke-width: 2 tooltip: "uint32 Big-Endian: Total message length excluding this field" width: 140 height: 120 }
type: "Type\n(1 Byte)" { style.fill: "${colors.header}" style.stroke: "${colors.border}" style.stroke-width: 2 tooltip: "MessageType Enum: Determines Body deserialization logic" width: 100 height: 120 }
node_id_len: "NodeIDLen\n(1 Byte)" { style.fill: "${colors.header}" style.stroke: "${colors.border}" style.stroke-width: 2 tooltip: "uint8: Length of NodeID string (N)" width: 100 height: 120 }
node_id: "NodeID\n(N Bytes)" { style.fill: "${colors.data}" style.stroke: "${colors.border}" style.stroke-width: 2 style.stroke-dash: 3 tooltip: "UTF-8 Unique Identifier of the originating node" width: 180 height: 120 }
timestamp: "Timestamp\n(8 Bytes)" { style.fill: "${colors.data}" style.stroke: "${colors.border}" style.stroke-width: 2 tooltip: "int64: Unix Nanoseconds BE. Used for vector clock drift detection." width: 180 height: 120 }
body: "Body Payload\n(Variable)" { style.fill: "${colors.free}" style.stroke: "${colors.border}" style.stroke-width: 2 style.stroke-dash: 5 tooltip: "Type-specific serialized data (e.g., PeerDigest list for SYNC)" width: 250 height: 120 }
# Connections for layout ordering length -> type -> node_id_len -> node_id -> timestamp -> body

div.p:
field_sizes: {
near: top-right
s1: "uint32" {shape: text}
s2: "uint8" {shape: text}
s3: "uint8" {shape: text}
s4: "string" {shape: text}
s5: "int64" {shape: text}
s6: "blob" {shape: text}
}

peer_digest: {
label: "Sub-Structure: PeerDigest (Serialized in Body Segment)"
style: {
stroke: "#F59E0B"
stroke-width: 2
stroke-dash: 4
fill: "#FFFBEB"
}

pre.code:
id_len: "IDLen\n(1B)" {style.fill: "${colors.header}"; width: 70; height: 90}
id_val: "ID String\n(N Bytes)" {style.fill: "${colors.data}"; width: 140; height: 90}
addr_len: "AddrLen\n(1B)" {style.fill: "${colors.header}"; width: 70; height: 90}
addr_val: "IP Address\n(M Bytes)" {style.fill: "${colors.data}"; width: 140; height: 90}
port: "Port\n(2B BE)" {style.fill: "${colors.data}"; width: 90; height: 90}
state: "State\n(1B)" {style.fill: "${colors.padding}"; width: 70; height: 90}
incarnation: "Incarnation\n(8B BE)" {style.fill: "${colors.data}"; width: 140; height: 90}

id_len -> id_val -> addr_len -> addr_val -> port -> state -> incarnation
